{"output": ""use client"
import { AdminShell, useAdminAuth } from "@/components/admin/admin-layout"
import { useState, useEffect } from "react"
import Link from "next/link"

type Post = { slug: string; title: string; excerpt: string; content: string; category: string; image_url: string; author: string; published: boolean; created_at: string }

function slugify(text: string) { return text.toLowerCase().replace(/[^\w\s-]/g, "").replace(/\s+/g, "-").slice(0, 60) }

export default function AdminBlog() {
  const { authed } = useAdminAuth()
  const [posts, setPosts] = useState<Post[]>([])
  const [showForm, setShowForm] = useState(false)
  const [editing, setEditing] = useState<string | null>(null)
  const [form, setForm] = useState<Post>({ slug: "", title: "", excerpt: "", content: "", category: "general", image_url: "", author: "", published: false, created_at: new Date().toISOString().split("T")[0] })
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (!authed) return
    load()
  }, [authed])

  const load = async () => {
    const res = await fetch("/api/admin/blog")
    if (res.ok) setPosts(await res.json())
  }

  const save = async () => {
    setLoading(true)
    if (!form.slug) form.slug = slugify(form.title)
    const method = editing ? "PATCH" : "POST"
    const res = await fetch("/api/admin/blog", {
      method, headers: { "Content-Type": "application/json" },
      body: JSON.stringify(editing ? { ...form, original_slug: editing } : form),
    })
    if (res.ok) { setShowForm(false); setEditing(null); setForm({ slug: "", title: "", excerpt: "", content: "", category: "general", image_url: "", author: "", published: false, created_at: new Date().toISOString().split("T")[0] }); load() }
    setLoading(false)
  }

  const remove = async (slug: string) => {
    if (!confirm("¿Eliminar este post?")) return
    await fetch("/api/admin/blog?slug=" + slug, { method: "DELETE" })
    load()
  }

  const categories = ["general", "camping", "pesca", "outdoor", "consejos"]

  if (!authed) return null

  return (
    <>
      <div className="mb-6 flex items-center justify-between">
        <h1 className="text-2xl font-bold text-white">Blog ({posts.length})</h1>
        <button onClick={() => { setShowForm(!showForm); setEditing(null); setForm({ slug: "", title: "", excerpt: "", content: "", category: "general", image_url: "", author: "", published: false, created_at: new Date().toISOString().split("T")[0] }) }}
          className="rounded-lg bg-emerald-600 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-500">
          {showForm ? "Cancelar" : "+ Nuevo post"}
        </button>
      </div>

      {showForm && (
        <div className="mb-6 rounded-xl border border-zinc-800/60 bg-zinc-900/50 p-6 space-y-4">
          <h3 className="font-semibold text-white">{editing ? "Editar post" : "Nuevo post"}</h3>
          <div className="grid grid-cols-2 gap-4">
            <input value={form.title} onChange={e => setForm({...form, title: e.target.value, slug: editing ? form.slug : slugify(e.target.value) })} placeholder="Título" className="rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            <input value={form.slug} onChange={e => setForm({...form, slug: e.target.value})} placeholder="Slug (URL)" className="rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white text-zinc-400" />
          </div>
          <div className="grid grid-cols-3 gap-4">
            <select value={form.category} onChange={e => setForm({...form, category: e.target.value})} className="rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white">
              {categories.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <input value={form.author} onChange={e => setForm({...form, author: e.target.value})} placeholder="Autor" className="rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            <input type="date" value={form.created_at} onChange={e => setForm({...form, created_at: e.target.value})} className="rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
          </div>
          <input value={form.image_url} onChange={e => setForm({...form, image_url: e.target.value})} placeholder="URL de imagen (opcional)" className="w-full rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
          <textarea value={form.excerpt} onChange={e => setForm({...form, excerpt: e.target.value})} placeholder="Extracto (breve descripción para la tarjeta)" rows={2} className="w-full rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
          <textarea value={form.content} onChange={e => setForm({...form, content: e.target.value})} placeholder="Contenido completo (markdown o HTML simple)" rows={8} className="w-full rounded bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white font-mono" />
          <label className="flex items-center gap-2 text-sm text-zinc-400">
            <input type="checkbox" checked={form.published} onChange={e => setForm({...form, published: e.target.checked})} className="text-emerald-600" />
            Publicado (visible en el sitio)
          </label>
          <button onClick={save} disabled={loading || !form.title}
            className="rounded-lg bg-emerald-600 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-500 disabled:opacity-50">
            {loading ? "Guardando..." : "Guardar"}
          </button>
        </div>
      )}

      {posts.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-zinc-500">
          <svg className="w-12 h-12 mb-4 text-zinc-400" fill="none" viewBox="[REDACTED_PHONE]" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M19 20H5a[REDACTED_PHONE]V6a[REDACTED_PHONE]h10a[REDACTED_PHONE]v1m2 13a[REDACTED_PHONE]V7m2 13a[REDACTED_PHONE]V9a[REDACTED_PHONE]h-2m-4-3H9M7 16h6M7 8h6v4H7V8z" /></svg>
          <p className="text-sm text-zinc-500">Sin posts todavía</p>
          <p className="text-xs text-zinc-400 mt-1">Creá el primero</p>
        </div>
      ) : (
        <div className="space-y-3">
          {posts.map(p => (
            <div key={p.slug} className="flex items-center justify-between rounded-xl border border-zinc-800/60 bg-zinc-900/50 p-4">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <h3 className="font-semibold text-white truncate">{p.title}</h3>
                  {p.published ? <span className="rounded-full bg-green-900/30 px-2 py-0.5 text-xs text-green-400">Publicado</span> : <span className="rounded-full bg-yellow-900/30 px-2 py-0.5 text-xs text-yellow-400">Borrador</span>}
                </div>
                <p className="text-xs text-zinc-500 mt-1">{p.category} · {p.created_at?.slice(0, 10)} · /blog/{p.slug}</p>
              </div>
              <div className="flex items-center gap-2 shrink-0 ml-4">
                <Link href={"/blog/" + p.slug} target="_blank" className="text-xs text-blue-400 hover:underline">Ver</Link>
                <button onClick={() => { setForm(p); setEditing(p.slug); setShowForm(true) }} className="text-xs text-amber-400 hover:underline">Editar</button>
                <button onClick={() => remove(p.slug)} className="text-xs text-red-400 hover:underline">Eliminar</button>
              </div>
            </div>
          ))}
        </div>
      )}
    </>
  )
}", "exit_code": 0, "error": null}

{"output": ""use client"
import { AdminShell, useAdminAuth } from "@/components/admin/admin-layout"
import { useState, useEffect } from "react"
import { PageHeader, SearchInput, EmptyState, TableSkeleton } from "@/components/admin/ui"

export default function AdminPromos() {
  const { authed } = useAdminAuth()
  const [promos, setPromos] = useState<any[]>([])
  const [showForm, setShowForm] = useState(false)
  const [editingCode, setEditingCode] = useState<string | null>(null)
  const [search, setSearch] = useState("")
  const [loading, setLoading] = useState(true)
  const [form, setForm] = useState({ code: "", type: "percentage", value: 10, minPurchase: 0, maxUses: 100, validFrom: "", validUntil: "" })

  useEffect(() => {
    if (!authed) return
    setLoading(true)
    fetch("/api/admin/promos").then(r => r.json()).then(data => { if (Array.isArray(data)) setPromos(data); setLoading(false) })
  }, [authed])

  const filtered = search ? promos.filter(p => p.code.toLowerCase().includes(search.toLowerCase())) : promos

  const resetForm = () => setForm({ code: "", type: "percentage", value: 10, minPurchase: 0, maxUses: 100, validFrom: "", validUntil: "" })

  const save = async () => {
    const method = editingCode ? "PATCH" : "POST"
    const body: any = { code: form.code, type: form.type, value: form.value, min_purchase: form.minPurchase, max_uses: form.maxUses }
    if (form.validFrom) body.valid_from = form.validFrom
    if (form.validUntil) body.valid_until = form.validUntil
    if (editingCode) body.original_code = editingCode

    const res = await fetch("/api/admin/promos", { method, headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) })
    if (res.ok) {
      resetForm()
      setShowForm(false)
      setEditingCode(null)
      fetch("/api/admin/promos").then(r => r.json()).then(data => { if (Array.isArray(data)) setPromos(data) })
    }
  }

  const remove = async (code: string) => {
    await fetch("/api/admin/promos?code=" + code, { method: "DELETE" })
    setPromos(promos.filter(p => p.code !== code))
  }

  const edit = async (p: any) => {
    setForm({
      code: p.code,
      type: p.type || "percentage",
      value: p.value || 10,
      minPurchase: p.min_purchase || 0,
      maxUses: p.max_uses || 100,
      validFrom: p.valid_from ? p.valid_from.slice(0, 10) : "",
      validUntil: p.valid_until ? p.valid_until.slice(0, 10) : "",
    })
    setEditingCode(p.code)
    setShowForm(true)
  }

  if (!authed) return null

  return (
    <>
      <PageHeader
        title={"Códigos Promocionales (" + promos.length + ")"}
        actions={
          <div className="flex items-center gap-3">
            <SearchInput value={search} onChange={setSearch} placeholder="Buscar código..." />
            <button onClick={() => { setShowForm(!showForm); setEditingCode(null); resetForm() }}
              className="rounded-lg bg-emerald-600 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-500">
              {showForm ? "Cancelar" : "+ Nuevo"}
            </button>
          </div>
        }
      />
      {showForm && (
        <div className="mb-6 rounded-xl border border-zinc-800/60 bg-zinc-900/50 p-4 space-y-3">
          <h3 className="text-sm font-semibold text-white">{editingCode ? "Editar " + editingCode : "Nuevo código"}</h3>
          <div className="grid grid-cols-2 gap-3">
            <input value={form.code} onChange={e => setForm({...form, code: e.target.value.toUpperCase()})} placeholder="CÓDIGO"
              className="rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            <select value={form.type} onChange={e => setForm({...form, type: e.target.value})}
              className="rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white">
              <option value="percentage">% Descuento</option>
              <option value="fixed">Gs. fijo</option>
            </select>
          </div>
          <div className="grid grid-cols-3 gap-3">
            <input type="number" value={form.value} onChange={e => setForm({...form, value: parseInt(e.target.value) || 0})}
              placeholder="Valor" className="rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            <input type="number" value={form.minPurchase} onChange={e => setForm({...form, minPurchase: parseInt(e.target.value) || 0})}
              placeholder="Compra mín. Gs." className="rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            <input type="number" value={form.maxUses} onChange={e => setForm({...form, maxUses: parseInt(e.target.value) || 1})}
              placeholder="Usos máx." className="rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="mb-1 block text-xs text-zinc-500">Válido desde</label>
              <input type="date" value={form.validFrom} onChange={e => setForm({...form, validFrom: e.target.value})}
                className="w-full rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            </div>
            <div>
              <label className="mb-1 block text-xs text-zinc-500">Válido hasta</label>
              <input type="date" value={form.validUntil} onChange={e => setForm({...form, validUntil: e.target.value})}
                className="w-full rounded-lg bg-zinc-800 border border-zinc-700/60 px-3 py-2 text-sm text-white" />
            </div>
          </div>
          <button onClick={save}
            className="rounded-lg bg-emerald-600 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-500">
            {editingCode ? "Guardar cambios" : "Crear código"}
          </button>
        </div>
      )}
      {loading ? (
        <TableSkeleton rows={4} cols={1} />
      ) : filtered.length === 0 ? (
        <EmptyState
          icon={
            <svg className="w-8 h-8" fill="none" viewBox="[REDACTED_PHONE]" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 8v13m0-13V6a[REDACTED_PHONE]h-2zm0 0V5.5A2.5 2.5 0 109.5 8H12zm-7 4h14M5 12a[REDACTED_PHONE]h14a[REDACTED_PHONE]M5 12v7a[REDACTED_PHONE]h10a[REDACTED_PHONE]v-7" />
            </svg>
          }
          title={search ? "Sin resultados" : "Sin códigos promocionales"}
        />
      ) : (
        <div className="space-y-2">
          {filtered.map((p: any) => {
            const expired = p.valid_until && new Date(p.valid_until) < new Date()
            return (
              <div key={p.code} className="flex items-center justify-between rounded-xl border border-zinc-800/60 bg-zinc-900/50 p-4 hover:border-zinc-700/60 transition-all group">
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <p className="font-bold text-white">{p.code}</p>
                    {expired && <span className="rounded-full bg-red-900/30 px-2 py-0.5 text-xs text-red-400">Expirado</span>}
                  </div>
                  <p className="text-xs text-zinc-500">
                    {p.type === "percentage" ? `${p.value}%` : `Gs. ${(p.value || 0).toLocaleString("es-PY")}`}
                    {" · "}min Gs. {(p.min_purchase || 0).toLocaleString("es-PY")}
                    {" · "}{p.used_count || 0}/{p.max_uses || 100} usos
                    {p.valid_until && ` · hasta ${new Date(p.valid_until).toLocaleDateString("es")}`}
                  </p>
                </div>
                <div className="flex items-center gap-2 shrink-0 ml-4">
                  <button onClick={() => edit(p)} className="text-xs text-blue-400 hover:underline">Editar</button>
                  <button onClick={() => remove(p.code)} className="text-xs text-red-400 hover:underline">Eliminar</button>
                </div>
              </div>
            )
          })}
        </div>
      )}
    </>
  )
}
